def _deep_merge_feature(old_value: Any, new_value: Any) -> Any:
    """Recursively merge ``new_value`` into ``old_value`` when both are dictionaries
    (or :class:`Sequence` objects wrapping dictionaries), otherwise ``new_value`` wins."""
    if isinstance(old_value, dict) and isinstance(new_value, dict):
        merged = dict(old_value)
        for key, value in new_value.items():
            merged[key] = _deep_merge_feature(merged[key], value) if key in merged else value
        return merged
    if (
        isinstance(old_value, Sequence)
        and isinstance(new_value, Sequence)
        and isinstance(old_value.feature, dict)
        and isinstance(new_value.feature, dict)
    ):
        return replace(old_value, feature=_deep_merge_feature(old_value.feature, new_value.feature))
    return new_value


